flow-diagram.createChart:
{
	person   = reactFlowBorder(reactFlowPadding(reactFlowText('Person'),   all: 5));
	company  = reactFlowBorder(reactFlowPadding(reactFlowText('Company'),  all: 5));
	address  = reactFlowBorder(reactFlowPadding(reactFlowText('Address'),  all: 5));
	order    = reactFlowBorder(reactFlowPadding(reactFlowText('Order'),    all: 5));
	product  = reactFlowBorder(reactFlowPadding(reactFlowText('Product'),  all: 5));
	category = reactFlowBorder(reactFlowPadding(reactFlowText('Category'), all: 5));

	reactFlowChart(
		reactFlowPadding(
			reactFlowGraphLayout(
				list($person, $company, $address, $order, $product, $category),
				list(
					reactFlowGraphEdge($person, $company,
						priority: 3,
						targetSymbol: "FILLED_ARROW"),
					reactFlowGraphEdge($person, $address,
						priority: 1,
						targetSymbol: "ARROW",
						decorations: list(
							reactFlowDecoration(reactFlowPadding(reactFlowText("address\n0..1", fontSize: "10"), all: 2), linePosition: 1.0, offsetPosition: "CENTER_LEFT")
						)),
					reactFlowGraphEdge($person, $order,
						priority: 1,
						targetSymbol: "ARROW",
						decorations: list(
							reactFlowDecoration(reactFlowPadding(reactFlowText("orders\n*", fontSize: "10"), all: 2), linePosition: 1.0, offsetPosition: "CENTER_LEFT")
						)),
					reactFlowGraphEdge($order, $product,
						priority: 2,
						sourceSymbol: "FILLED_DIAMOND",
						decorations: list(
							reactFlowDecoration(reactFlowPadding(reactFlowText("1", fontSize: "10"), all: 2), linePosition: 0.0, offsetPosition: "CENTER_LEFT"),
							reactFlowDecoration(reactFlowPadding(reactFlowText("items\n1..*", fontSize: "10"), all: 2), linePosition: 1.0, offsetPosition: "CENTER_LEFT")
						)),
					reactFlowGraphEdge($product, $category,
						priority: 1,
						targetSymbol: "ARROW",
						decorations: list(
							reactFlowDecoration(reactFlowPadding(reactFlowText("category\n1", fontSize: "10"), all: 2), linePosition: 1.0, offsetPosition: "CENTER_LEFT")
						))
				)
			),
			all: 20
		)
	)
}
